            dp[i] = dp[i-1];
            long residue = P[i] % k;
            if (map.containsKey(residue)) {
                long candidate = map.get(residue);
                long option = candidate + P[i];
                if (option > dp[i]) {
                    dp[i] = option;
                }
            }
            long currentCandidate = dp[i] - P[i];
            if (map.containsKey(residue)) {
